INSERT INTO `teksty` (`id`, `tytul`, `tresc`, `kluczowe_g`, `tytul_g`, `opis_g`, `gal`, `tytul2`, `tresc2`, `tytul3`, `tresc3`) VALUES
(1, 'Home banner', '&lt;p&gt;Firma PGM Enginering, z siedzibą w Pruszkowie, została założona w 2012 roku przez Krzysztofa Bartosiewicza. Specjalizujemy się w instalacjach i reinstalacjach urządzeń poligraficznych, zapewniając kompleksową obsługę zar&oacute;wno na terenie kraju, jak i zagranicy.&lt;/p&gt;', '', '', '', 0, '', '&lt;p&gt;Established in 2012 by Krzysztof Bartosiewicz, PGM Engineering is headquatered in Pruszk&oacute;w. It specializes in dismantlings and reassemblings of printing machinery, providing end-to-end service both in Poland and Worldwide.&lt;/p&gt;', '', 'PGM Engineering, mit Sitz in Pruszk&oacute;w, wurde 2012 von Krzysztof Bartosiewicz gegr&uuml;ndet. Wir sind auf die Montage, Umzug und Remontage von Druckanlagen spezialisiert und bieten umfassende Dienstleistungen im In- und Ausland an.'),
(2, 'Home Montaż i serwis maszyn poligraficznych', '&lt;p&gt;Firma PGM Enginering, z siedzibą w Pruszkowie, została założona w 2012 roku przez Krzysztofa Bartosiewicza. Specjalizujemy się w instalacjach i reinstalacjach urządzeń poligraficznych, zapewniając kompleksową obsługę zar&oacute;wno na terenie kraju, jak i zagranicy.&lt;br /&gt;\r\n&lt;br /&gt;\r\nOd początku działalności postawiliśmy na nieustanny rozw&oacute;j przedsiębiorstwa, jak i na wysoką jakość świadczonych usług, dlatego regularnie bierzemy udział w targach branżowych, i wszelkiego rodzaju szkoleniach z zakresu budowy i eksploatacji maszyn poligraficznych, a nasze urządzenia trafiają do firm na całym świecie.&lt;/p&gt;', '', '', '', 0, '', '&lt;p&gt;Established in 2012 by Krzysztof Bartosiewicz, PGM Engineering is headquatered in Pruszk&oacute;w. It specializes in dismantlings and reassemblings of printing machinery, providing end-to-end service both in Poland and Worldwide.&lt;br /&gt;\r\n&lt;br /&gt;\r\nFrom the very begining our primary focus has been on continous development of company and top-tier quality of services provided.&amp;#160; In pursuit of our commitment to excellence, we actively participate in industry fairs and training programs focused on the construction and operation of printing machinery.&lt;/p&gt;', '', '&lt;p&gt;PGM Engineering, mit Sitz in Pruszk&oacute;w, wurde 2012 von Krzysztof Bartosiewicz gegr&uuml;ndet. Wir sind auf die Montage, Umzug und Remontage von Druckanlagen spezialisiert und bieten umfassende Dienstleistungen im In- und Ausland an.&lt;br /&gt;\r\n&lt;br /&gt;\r\nSeit Beginn unserer T&auml;tigkeit legen wir Wert auf kontinuierliche Weiterentwicklung des Unternehmens und hohe Leistungsqualit&auml;t. Deshalb nehmen wir regelm&auml;&szlig;ig an Branchenmessen und Schulungen im Bereich des Baus und Betriebs von Druckmaschinen teil. Unsere Maschinen werden an Unternehmen auf der ganzen Welt geliefert.&lt;/p&gt;'),
(3, 'Home Nasza oferta', '&lt;p&gt;Firma PGM Enginering, z siedzibą w Pruszkowie, została założona w 2012 roku przez Krzysztofa Bartosiewicza. Specjalizujemy się w instalacjach i reinstalacjach urządzeń poligraficznych, zapewniając kompleksową obsługę zar&oacute;wno na terenie kraju, jak i zagranicy.&lt;/p&gt;', '', '', '', 0, '', '&lt;p&gt;Established in 2012 by Krzysztof Bartosiewicz, PGM Engineering is headquatered in Pruszk&oacute;w. It specializes in dismantlings and reassemblings of printing machinery, providing end-to-end service both in Poland and Worldwide.&lt;/p&gt;', '', '&lt;p&gt;PGM Engineering, mit Sitz in Pruszk&oacute;w, wurde 2012 von Krzysztof Bartosiewicz gegr&uuml;ndet. Wir sind auf die Montage, Umzug und Remontage von Druckanlagen spezialisiert und bieten umfassende Dienstleistungen im In- und Ausland an.&lt;/p&gt;'),
(4, 'Home Doradztwo w wyborze maszyn poligraficznych', '&lt;p&gt;Firma PGM Enginering, z siedzibą w Pruszkowie, została założona w 2012 roku przez Krzysztofa Bartosiewicza. Specjalizujemy się w instalacjach i reinstalacjach urządzeń poligraficznych, zapewniając kompleksową obsługę zar&oacute;wno na terenie kraju, jak i zagranicy.&lt;/p&gt;', '', '', '', 0, '', '&lt;p&gt;Established in 2012 by Krzysztof Bartosiewicz, PGM Engineering is headquatered in Pruszk&oacute;w. It specializes in dismantlings and reassemblings of printing machinery, providing end-to-end service both in Poland and Worldwide.&lt;/p&gt;', '', '&lt;p&gt;PGM Engineering, mit Sitz in Pruszk&oacute;w, wurde 2012 von Krzysztof Bartosiewicz gegr&uuml;ndet. Wir sind auf die Montage, Umzug und Remontage von Druckanlagen spezialisiert und bieten umfassende Dienstleistungen im In- und Ausland an.&lt;/p&gt;'),
(5, 'Home Dlaczego wybrać nas', '&lt;p&gt;Firma PGM Enginering, z siedzibą w Pruszkowie, została założona w 2012 roku przez Krzysztofa Bartosiewicza. Specjalizujemy się w instalacjach i reinstalacjach urządzeń poligraficznych, zapewniając kompleksową obsługę zar&oacute;wno na terenie kraju, jak i zagranicy.&lt;/p&gt;', '', '', '', 0, '', '&lt;p&gt;Established in 2012 by Krzysztof Bartosiewicz, PGM Engineering is headquatered in Pruszk&oacute;w. It specializes in dismantlings and reassemblings of printing machinery, providing end-to-end service both in Poland and Worldwide.&lt;/p&gt;', '', 'PGM Engineering, mit Sitz in Pruszk&oacute;w, wurde 2012 von Krzysztof Bartosiewicz gegr&uuml;ndet. Wir sind auf die Montage, Umzug und Remontage von Druckanlagen spezialisiert und bieten umfassende Dienstleistungen im In- und Ausland an.'),
(6, 'polityka-prywatnosci', 'polityka-prywatnosci', '', '', '', 0, '', '', '', ''),
(7, 'Maszyny dla poligrafii', '&lt;p&gt;Procesy technologiczne ulegają ciągłym zmianom - priorytetem stał sie czas i automatyzacja procesu. Dotyczy to także szeroko pojętej poligrafii i braku personelu Jednym z system&oacute;w mających na celu optymalizację czasu i ludzi są offline oczyszczarki arkusza.&lt;br /&gt;\r\n&lt;br /&gt;\r\nProsta i intuicyjna obsługa. polski interfejs pozwala na szybkie uzbrajanie maszyn bez konieczności stosowania specjalnych matryc. Wysztancowane arkusze są oczyszczane z pojedynczych pakiet&oacute;w użytk&oacute;w aż do uzyskania czystego ażuru.&lt;br /&gt;\r\n&lt;br /&gt;\r\nMożliwość r&oacute;żnorodnej konfiguracji pozwala nam dostarczyć maszynę od najprostszej do maksymalnie rozbudowanej wersji z automatycznym odkładaniem na palety. Atutem tego rozwiązania jest jednoosobowa obsługa maszyny&lt;/p&gt;', '', '', '', 1, 'Machines for printing', '&lt;p&gt;Technological advancements continue to evolve, emphasizing the importance of time efficiency and process automation. This trend extends to various sectors, including the printing industry, where addressing labor shortages and optimizing workflow are paramount. Tearing machines are one such system designed to streamline operations.&lt;br /&gt;\r\n&lt;br /&gt;\r\nFeaturing a user-friendly interface, these machines offer simple and intuitive operation. Their Polish interface facilitates quick setup without the need for special matrices. The machines effectively clean die-cut sheets in individual bundles until achieving a pristine, openwork finish.&lt;br /&gt;\r\n&lt;br /&gt;\r\nThe flexibility of these machines allows for various configurations, ranging from basic models to advanced versions equipped with automatic pallet placement. Notably, this solution enables single-operator functionality, enhancing operational efficiency.&lt;/p&gt;', 'Maschinen zum Drucken', '&lt;p&gt;Technologische Prozesse &auml;ndern sich st&auml;ndig &ndash; Zeit und Prozessautomatisierung stehen heute im Vordergrund. Das gilt auch f&uuml;r die Druckindustrie und den Personalmangel. Eines der Systeme zur Optimierung von Zeit und Arbeitskraft ist die automatische Bogenreinigungsmaschine.&lt;br /&gt;\r\n&lt;br /&gt;\r\nLeichte und intuitive Bedienung sowie die einfache Benutzeroberfl&auml;che erm&ouml;glichen schnelle Einrichtung der Maschine, ohne Verwendung spezieller Matrizen. Die gestanzten B&ouml;gen werden von einzelnen B&uuml;ndeln gereinigt, bis eine saubere Oberfl&auml;che erreicht ist.&lt;br /&gt;\r\n&lt;br /&gt;\r\nDie M&ouml;glichkeit verschiedener Konfigurationen erlaubt es uns, eine Maschine von der einfachsten bis zur umfangreichsten Version mit automatischer Palettierung zu liefern. Der Vorteil dieser L&ouml;sung ist die Ein-Mann-Bedienung.&lt;/p&gt;'),
(8, 'Serwis i transport', '&lt;p&gt;Wybierz naszą firmę, jeśli potrzebujesz niezawodnego i profesjonalnego partnera w transporcie oraz serwisie maszyn poligraficznych. Z wieloletnim doświadczeniem i wysokimi standardami obsługi, zapewniamy kompleksowe rozwiązania, kt&oacute;re sprostają Twoim oczekiwaniom. &lt;br /&gt;\r\n&lt;br /&gt;\r\nNasz zesp&oacute;ł wyspecjalizowanych mechanik&oacute;w i specjalist&oacute;w ds. logistyki dba o każdy szczeg&oacute;ł, zapewniając bezpieczne i terminowe dostarczenie Twoich maszyn. &lt;br /&gt;\r\n&lt;br /&gt;\r\nWybierz naszą firmę, a otrzymasz nie tylko profesjonalizm, ale także pełne zaangażowanie i indywidualne podejście. Skorzystaj z naszej solidnej reputacji i oddaj swoje zaufanie w ręce ekspert&oacute;w.&lt;/p&gt;', '', '', '', 1, 'Service and transport', '&lt;p&gt;Choose&amp;#160; our company as your trusted and professional partner for the transportation and servicing of printing machinery. With years of expertise and unwavering service standards, we offer comprehensive solutions tailored to exceed your expectations.&lt;br /&gt;\r\n&lt;br /&gt;\r\nOur dedicated team of specialized mechanics and logistics experts meticulously oversee every detail, guaranteeing the secure and punctual delivery of your machinery.&lt;br /&gt;\r\n&lt;br /&gt;\r\nSelect our company and experience not only professionalism, but also unwavering dedication and personalized attention. Benefit from our strong reputation and entrust your needs to the hands of seasoned experts.&lt;/p&gt;', 'Service und Transport', '&lt;p&gt;W&auml;hlen Sie unsere Firma, wenn Sie einen zuverl&auml;ssigen und professionellen Partner f&uuml;r Transport und Service von Druckmaschinen ben&ouml;tigen. Mit langj&auml;hriger Erfahrung und hohen Servicestandards bieten wir umfassende L&ouml;sungen, die Ihre Erwartungen erf&uuml;llen. &lt;br /&gt;\r\n&lt;br /&gt;\r\nUnser Team von spezialisierten Mechanikern und Logistikern k&uuml;mmert sich um jedes Detail, um eine sichere und p&uuml;nktliche Lieferung Ihrer Maschinen zu gew&auml;hrleisten. &lt;br /&gt;\r\n&lt;br /&gt;\r\nW&auml;hlen Sie unser Unternehmen und Sie erhalten nicht nur Professionalit&auml;t, sondern auch volles Engagement und individuelle Herangehensweise. Profitieren Sie von unserem guten Ruf und vertrauen Sie unseren Experten.&lt;/p&gt;'),
(9, 'Doradztwo', '&lt;p&gt;Jesteśmy specjalistycznym zespołem ekspert&oacute;w, kt&oacute;rzy posiadają bogate doświadczenie w branży poligraficznej. &lt;br /&gt;\r\n&lt;br /&gt;\r\nNaszym celem jest dostarczenie naszym klientom kompleksowej wiedzy i wsparcia w zakresie zakupu, użytkowania i konserwacji maszyn poligraficznych. Oferujemy indywidualne konsultacje, podczas kt&oacute;rych odpowiemy na wszystkie Państwa pytania i pomożemy w doborze najlepszego rozwiązania dla Państwa potrzeb. Naszą misją jest zapewnienie pełnego wsparcia i doradztwa w procesie zakupowym, aby nasi klienci mogli podejmować świadome decyzje. &lt;br /&gt;\r\n&lt;br /&gt;\r\nDołącz do naszego grona zadowolonych klient&oacute;w i ciesz się profesjonalnym doradztwem w zakresie maszyn poligraficznych.&lt;/p&gt;', '', '', '', 1, 'Consulting', '&lt;p&gt;We are a dedicated team of seasoned professionals with extensive expertise in the printing industry.&lt;br /&gt;\r\n&lt;br /&gt;\r\nOur objective is to furnish our clients with comprehensive guidance and assistance throughout the procurement, utilization, and maintenance phases of printing machinery. We offer personalized consultations wherein we address all inquiries and aid in selecting the optimal solution tailored to individual requirements. Our mission is to deliver thorough support and advisory services throughout the purchasing journey, empowering our clients to make well-informed decisions.&lt;br /&gt;\r\n&lt;br /&gt;\r\nJoin our community of satisfied clientele and benefit from expert counsel on printing machinery.&lt;/p&gt;', 'Beratung', '&lt;p&gt;Wir sind ein spezialisiertes Team von Fachleuten mit langj&auml;hriger Erfahrung in der Druckindustrie. &lt;br /&gt;\r\n&lt;br /&gt;\r\nUnser Ziel ist es, unsere Kunden mit umfassendem Know-How und Unterst&uuml;tzung bei Kauf, Betrieb und Wartung von Druckmaschinen zu versorgen. Wir bieten Ihnen eine individuelle Beratung, bei der wir alle Ihre Fragen beantworten und Ihnen helfen, die beste L&ouml;sung f&uuml;r Ihre Bed&uuml;rfnisse zu finden. Unsere Mission ist es, vielseitige Betreuung und Beratung w&auml;hrend des Kaufprozesses zu bieten, damit unsere Kunden fundierte Entscheidungen treffen k&ouml;nnen.&lt;br /&gt;\r\n&lt;br /&gt;\r\nSchlie&szlig;en Sie sich unserem Kreis zufriedener Kunden an und genie&szlig;en Sie professionelle Beratung im Bereich der Druckmaschinen.&lt;/p&gt;'),
(10, 'Galeria', '', '', '', '', 1, 'Gallery', '', 'Galerie', ''),
(11, 'Kontakt z nami', '&lt;p&gt;Dziękujemy, ze odwiedzasz naszą stronę internetowa! Jeśli szukasz profesjonalnej firmy specjalizującej się w relokacji maszyn poligraficznych, trafiłeś we właściwe miejsce.&lt;br /&gt;\r\n&lt;br /&gt;\r\nNasza firma ma wieloletnie doświadczenie w przeprowadzaniu kompleksowych usług związanych z przenoszeniem maszyn poligraficznych i introligatorskich. Nasi wysoko wykwalifikowani specjaliści doskonale znają się na wszystkich aspektach relokacji, od demontażu i pakowania po transport i montaż na nowym miejscu.&lt;br /&gt;\r\n&lt;br /&gt;\r\nJesteśmy dumni z wysokiej jakości usług, kt&oacute;re świadczymy naszym Klientom. Działamy sprawnie, terminowo i zawsze z najwyższą starannością, aby zapewnić, ze wszystkie maszyny są bezpiecznie przeniesione i zainstalowane.&lt;br /&gt;\r\n&lt;br /&gt;\r\nJeśli masz pytania dotyczące naszych usług, chcesz uzyskać wycenę, lub potrzebujesz porady eksperta, skontaktuj się z nami. Nasz zesp&oacute;ł jest dostępny, aby odpowiedzieć na Twoje pytania, udzielić niezbędnej pomocy i zaproponować najlepsze rozwiązania dla Twoich potrzeb.&lt;br /&gt;\r\n&lt;br /&gt;\r\nZapraszamy do kontaktu za pomocą poniższych danych kontaktowych lub poprzez formularz kontaktowy dostępny poniżej. Z przyjemnością pomożemy Ci w każdym związku z relokacją maszyn ze świata poligrafii.&lt;/p&gt;\r\n&lt;p&gt;&amp;#160;&lt;/p&gt;\r\n&lt;div class=&quot;cz_24 do_srodka&quot;&gt;Telefon: &lt;a href=&quot;tel:+48695563561&quot;&gt;+48 695 563 561&lt;/a&gt;\r\n&lt;div class=&quot;odstep_5&quot;&gt;&amp;#160;&lt;/div&gt;\r\nEmail: &lt;a href=&quot;mailto:servis@pgm-engineering.com&quot;&gt;servis@pgm-engineering.com&lt;/a&gt;\r\n&lt;div class=&quot;odstep_5&quot;&gt;&amp;#160;&lt;/div&gt;\r\nAdres: Sowia 1, 05-822 Milan&oacute;wek&lt;/div&gt;\r\n&lt;p&gt;&lt;br /&gt;\r\n&lt;br /&gt;\r\nCzekamy na Tw&oacute;j kontakt i bardzo chętnie odpowiemy na Twoje pytania.&lt;/p&gt;', '', '', '', 0, 'Contact Us', '&lt;p&gt;Thank you for visiting our website! If you are seeking a professional company specializing in the relocation of printing machinery, you have arrived at the right destination. &lt;br /&gt;\r\n&lt;br /&gt;\r\nWith years of experience, our company offers comprehensive services encompassing the transfer of printing and bookbinding machinery. Our team of highly skilled specialists possesses extensive knowledge across all facets of relocation, from meticulous dismantling and secure packing to seamless transport and precise assembly at the new site. &lt;br /&gt;\r\n&lt;br /&gt;\r\nWe take pride in delivering high-quality services to our clients, ensuring efficient, timely, and meticulous handling to guarantee the safe relocation and installation of all machinery. &lt;br /&gt;\r\n&lt;br /&gt;\r\nShould you have any inquiries regarding our services, require a quotation, or seek expert guidance, please do not hesitate to contact us. Our dedicated team is readily available to address your queries, provide necessary assistance, and propose optimal solutions tailored to your needs. &lt;br /&gt;\r\n&lt;br /&gt;\r\nPlease feel free to reach out to us using the contact details provided below or via the contact form available on our website. We are eager to assist you with any aspect related to the relocation of printing machinery./p&amp;gt;&lt;/p&gt;\r\n&lt;p&gt;&amp;#160;&lt;/p&gt;\r\n&lt;div class=&quot;cz_24 do_srodka&quot;&gt;Phone: &lt;a href=&quot;tel:+48695563561&quot;&gt;+48 695 563 561&lt;/a&gt;\r\n&lt;div class=&quot;odstep_5&quot;&gt;&amp;#160;&lt;/div&gt;\r\nEmail: &lt;a href=&quot;mailto:servis@pgm-engineering.com&quot;&gt;servis@pgm-engineering.com&lt;/a&gt;\r\n&lt;div class=&quot;odstep_5&quot;&gt;&amp;#160;&lt;/div&gt;\r\nAddress: Sowia 1, 05-822 Milan&oacute;wek&lt;/div&gt;\r\n&lt;p&gt;&lt;br /&gt;\r\n&lt;br /&gt;\r\nWe eagerly anticipate your correspondence and remain at your disposal to address any inquiries you may have.&lt;/p&gt;', 'Kontaktiere uns', '&lt;p&gt;Vielen Dank f&uuml;r Ihren Besuch auf unserer Website! Wenn Sie ein professionelles Unternehmen suchen, das sich auf den Umzug von Druckmaschinen spezialisiert hat, sind Sie bei uns genau richtig.&lt;br /&gt;\r\n&lt;br /&gt;\r\nUnsere Firma verf&uuml;gt &uuml;ber langj&auml;hrige Erfahrung in komplexen Dienstleistungen rund um den Umzug von Druck- und Buchbindereimaschinen.&amp;#160; Unsere hochqualifizierten Fachkr&auml;fte kennen sich bestens mit allen Aspekten des Umzugs aus, von der Demontage und Verpackung bis hin zum Transport und der Montage am neuen Standort.&lt;br /&gt;\r\n&lt;br /&gt;\r\nWir sind stolz auf die hohe Qualit&auml;t unserer Dienstleistungen. Wir arbeiten effizient, p&uuml;nktlich und stets mit gr&ouml;&szlig;ter Sorgfalt, damit alle Maschinen sicher verlegt und installiert werden.&lt;br /&gt;\r\n&lt;br /&gt;\r\nWenn Sie Fragen zu unseren Dienstleistungen haben, ein Preisangebot w&uuml;nschen oder eine fachkundige Beratung ben&ouml;tigen, setzen Sie sich mit uns in Kontakt. Unser Team ist f&uuml;r Sie da, um Ihre Fragen zu beantworten, Sie zu unterst&uuml;tzen und&amp;#160; die besten L&ouml;sungen f&uuml;r Sie vorzuschlagen.&lt;br /&gt;\r\n&lt;br /&gt;\r\nKontaktieren Sie uns unter den unten stehenden Kontaktdaten oder &uuml;ber das unten stehende Kontaktformular. Wir helfen Ihnen gerne bei allen Fragen rund um den Umzug von Maschinen aus der Druckbranche.&lt;br /&gt;\r\n&lt;br /&gt;\r\n&lt;br /&gt;\r\nTelefon: +48 695 563 561 &lt;br /&gt;\r\nE-Mail: servis@pgm-engineering.com &lt;br /&gt;\r\nAdresse: Sowia 1, PL-05-822 Milan&oacute;wek&lt;br /&gt;\r\n&lt;br /&gt;\r\n&lt;br /&gt;\r\nWir freuen uns, von Ihnen zu h&ouml;ren und beantworten gerne alle Ihre Fragen.&lt;/p&gt;'),
(12, 'O nas', '&lt;p&gt;PGM Engineering to nowoczesna firma specjalizująca się w relokacji maszyn poligraficznych. Dążymy do zapewnienia naszym Klientom najwyższej jakości usług w zakresie przenoszenia, montażu i demontażu maszyn poligraficznych. Nasze wieloletnie doświadczenie w branży oraz wysoko wykwalifikowana kadra gwarantują profesjonalne podejście i satysfakcje naszych Klient&oacute;w.&lt;br /&gt;\r\n&lt;br /&gt;\r\nNasza firma doskonale zdaje sobie sprawę z tego, jak ważne jest bezpieczne przeniesienie, montaż i demontaż maszyn, kt&oacute;re są często niezwykle skomplikowane i delikatne. Dlatego tez inwestujemy w nowoczesny sprzęt oraz ciągłe szkolenia naszego personelu. Dzięki temu jesteśmy w stanie zapewnić naszym klientom kompleksowe rozwiązania, kt&oacute;re spełniają najwyższe standardy branżowe.&lt;br /&gt;\r\n&lt;br /&gt;\r\nJako PGM Engineering oferujemy naszym klientom szereg usług, kt&oacute;re uwzględniają wszystkie etapy procesu relokacji maszyn poligraficznych. Nasi eksperci przeprowadzą szczeg&oacute;łową analizę, planowanie i przygotowanie maszyn do przeniesienia, uwzględniając zar&oacute;wno techniczne, jak i logistyczne aspekty. Następnie przystępujemy do samodzielnego demontażu, transportu i montażu maszyn w miejscu docelowym.&lt;br /&gt;\r\n&lt;br /&gt;\r\nBez względu na to, czy klient potrzebuje przeniesienia jednej maszyny, czy tez kompleksowej relokacji całej linii produkcyjnej, PGM Engineering jest gotowe sprostać tym wymaganiom. Nasza firma posiada odpowiednie zaplecze logistyczne oraz doświadczenie, aby zrealizować nawet najbardziej skomplikowane projekty. Ponadto, działamy zar&oacute;wno na terenie całego świata dlatego możemy zaspokoić potrzeby klient&oacute;w w r&oacute;żnych regionach.&lt;br /&gt;\r\n&lt;br /&gt;\r\nZaufanie naszych klient&oacute;w jest dla nas najważniejsze. Dlatego stawiamy na transparentność, terminowość i profesjonalizm. Zawsze dokładamy wszelkich starań, aby zapewnić bezpieczne i efektywne przeniesienie maszyn poligraficznych, minimalizując przest&oacute;j produkcji. Nasz priorytet to zadowolenie naszych klient&oacute;w i partner&oacute;w biznesowych.&lt;br /&gt;\r\n&lt;br /&gt;\r\nJeśli szukasz eksperta w dziedzinie relokacji maszyn poligraficznych, PGM Engineering jest firmą, na kt&oacute;rej możesz polegać. Zapraszamy do kontaktu, aby om&oacute;wić potrzeby Twojej firmy i znaleźć najlepsze rozwiązanie dla Ciebie.&lt;/p&gt;', '', '', '', 1, 'About us', '&lt;p&gt;PGM Engineering is a contemporary enterprise specializing in the relocation of printing machinery. Our commitment lies in delivering superior services encompassing the transfer, assembly, and disassembly of printing machinery. With extensive industry experience and a highly skilled workforce, we guarantee a professional approach and utmost client satisfaction.&lt;br /&gt;\r\n&lt;br /&gt;\r\nWe understand the critical importance of safely relocating, assembling, and dismantling machinery, often intricate and delicate in nature. Hence, we invest in state-of-the-art equipment and continually train our personnel. This enables us to provide clients with comprehensive solutions that adhere to the highest industry standards.&lt;br /&gt;\r\n&lt;br /&gt;\r\nAt PGM Engineering, we offer a comprehensive suite of services covering all facets of the printing machinery relocation process. Our experts conduct meticulous analysis, planning, and preparation of machinery for relocation, considering both technical and logistical aspects. Subsequently, we oversee the dismantling, transportation, and reassembly of machinery at the destination.&lt;br /&gt;\r\n&lt;br /&gt;\r\nWhether our clients require the relocation of a single machine or an extensive transfer of an entire production line, PGM Engineering is equipped to fulfill these needs. We possess the necessary logistics infrastructure and experience to handle even the most intricate projects. Furthermore, our operations span globally, enabling us to cater to clients across diverse regions.&lt;br /&gt;\r\n&lt;br /&gt;\r\nClient trust is paramount to us. Therefore, we prioritize transparency, punctuality, and professionalism in all our endeavors. We endeavor to ensure the safe and efficient relocation of printing machinery, minimizing production downtime. Ultimately, client satisfaction remains our foremost priority.&lt;br /&gt;\r\n&lt;br /&gt;\r\nIf you seek an expert in printing machinery relocation, PGM Engineering is your trusted partner. Contact us to discuss your company&#039;s requirements and discover tailored solutions best suited to your needs.&lt;/p&gt;', '&Uuml;ber uns', '&lt;p&gt;GM Engineering ist ein modernes Unternehmen, dessen Spezialgebiet die Verlagerung von Druckmaschinen ist.&amp;#160; Unser Ziel ist es, unseren Kunden in diesem Bereich das h&ouml;chste Niveau an Dienstleistungen zu bieten. Langj&auml;hrige Erfahrung in der Branche und hochqualifiziertes Personal garantieren professionelle Vorgehensweise und Zufriedenheit unserer Kunden.&lt;br /&gt;\r\n&lt;br /&gt;\r\nUnsere Firma ist sich der Bedeutung der ordnungsgem&auml;&szlig;en Demontage, des sicheren Transports und des Wiederaufbaus von Maschinen bewusst, die oft sehr komplex und empfindlich sind. Wir investieren in moderne Ausr&uuml;stung und st&auml;ndige Weiterbildung der Mitarbeiter. Dadurch sind wir in der Lage, ganzheitliche L&ouml;sungen zu bieten, die den h&ouml;chsten Standards entsprechen.&lt;br /&gt;\r\n&lt;br /&gt;\r\n&lt;br /&gt;\r\nDas Angebot von PGM Engineering umfasst eine Reihe von Dienstleistungen, die alle Phasen des Umzugsprozesses von Druckmaschinen einbeziehen. Von unseren Experten wird eine detaillierte Analyse, Planung und Vorbereitung der Maschine unter Ber&uuml;cksichtigung technischer und logistischer Aspekte durchgef&uuml;hrt. Anschlie&szlig;end wird die Maschine von uns demontiert, transportiert und am Bestimmungsort montiert.&lt;br /&gt;\r\n&lt;br /&gt;\r\nGanz gleich, ob Sie eine einzelne Maschine oder eine komplette Produktionslinie verlagern m&uuml;ssen, PGM Engineering ist bereit, diese Anforderungen zu erf&uuml;llen. Unser Unternehmen verf&uuml;gt &uuml;ber die entsprechende Logistik und Erfahrung, um auch die komplexesten Projekte umzusetzen. Da wir weltweit t&auml;tig sind, k&ouml;nnen wir Kunden in verschiedenen Regionen bedienen.&lt;br /&gt;\r\n&lt;br /&gt;\r\nDas Vertrauen unserer Kunden steht f&uuml;r uns an erster Stelle. Deshalb setzen wir auf Transparenz, Termintreue und Professionalit&auml;t. Wir sind stets bem&uuml;ht, einen sicheren und effizienten Transport der Druckmaschinen zu gew&auml;hrleisten, um Produktionsausf&auml;lle zu minimieren. Unsere Priorit&auml;t ist die Zufriedenheit unserer Kunden und Gesch&auml;ftspartner.&lt;br /&gt;\r\n&lt;br /&gt;\r\nWenn Sie einen Experten f&uuml;r Umz&uuml;ge von Druckmaschinen suchen, ist PGM Engineering der richtige Ansprechpartner f&uuml;r Sie. Gerne besprechen wir mit Ihnen die Details Ihres Bedarfs und finden beste L&ouml;sung f&uuml;r Sie.&lt;/p&gt;'),
(13, 'Relokacje, serwis maszyn', '&lt;p&gt;Oferta firmy PGM Engineering sp. z o.o. skierowana jest w szczeg&oacute;lności do firm działających w branży poligraficznej. &lt;br /&gt;\r\n&lt;br /&gt;\r\nJesteśmy po to by zapewnić Państwu kompleksową pomoc w wyborze oraz zakupie najbardziej odpowiednich maszyn, dostosowanych do specyfiki Waszego przedsiębiorstwa. Jednocześnie zajmujemy się przeprowadzaniem kompleksowych relokacji maszyn z dowolnego punktu na świecie. Bierzemy na swoje barki każdy aspekt związany z demontażem oraz ponowną instalacją i uruchomieniem maszyny. Prowadzimy r&oacute;wnież serwis poinstalacyjny.&lt;br /&gt;\r\n&lt;br /&gt;\r\nW profesjonalny spos&oacute;b przygotowujemy i zabezpieczamy maszyny na transport drogowy i morski.&lt;br /&gt;\r\n&lt;br /&gt;\r\n&lt;strong&gt;Proponujemy:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n    &lt;li&gt;wykonanie inspekcji oraz raport techniczny na powierzonej maszynie,&lt;/li&gt;\r\n    &lt;li&gt;deinstalację oraz instalację maszyny w miejscu wyznaczonym przez klienta,&lt;/li&gt;\r\n    &lt;li&gt;organizację transportu maszyn w każde miejsce na świecie.&lt;/li&gt;\r\n&lt;/ul&gt;', '', '', '', 1, 'Relocations, machine service', '&lt;p&gt;PGM Engineering&#039;s offerings are specifically tailored to companies within the printing industry.&lt;br /&gt;\r\n&lt;br /&gt;\r\nWe are committed to providing comprehensive assistance in selecting and acquiring the most suitable machinery, customized to the unique needs of your company. Additionally, we facilitate complete machine relocations from anywhere worldwide. Our services encompass all aspects of disassembly, reinstallation, and machine commissioning, with ongoing post-installation support.&lt;br /&gt;\r\n&lt;br /&gt;\r\nWe meticulously prepare and secure machinery for both road and sea transport.&lt;br /&gt;\r\n&lt;br /&gt;\r\n&lt;strong&gt;Our services include:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n    &lt;li&gt;Conducting inspections and providing technical reports on entrusted machinery.&lt;/li&gt;\r\n    &lt;li&gt;Undertaking machine disassembly and reinstallation at customer-designated locations.&lt;/li&gt;\r\n    &lt;li&gt;Organizing global transportation of machinery to any destination worldwide.&lt;/li&gt;\r\n&lt;/ul&gt;', 'Umz&uuml;ge, Maschinenservice', '&lt;p&gt;Das Angebot von PGM Engineering sp. z o.o. richtet sich insbesondere an Unternehmen, die in der Druckbranche t&auml;tig sind.&lt;br /&gt;\r\n&lt;br /&gt;\r\nWir bieten Ihnen umfassende Unterst&uuml;tzung bei der Auswahl und dem Kauf der geeigneten Maschinen, die an die Besonderheiten Ihres Unternehmens angepasst sind. Dar&uuml;ber hinaus f&uuml;hren wir komplexe Maschinenumz&uuml;ge weltweit durch. Wir k&uuml;mmern uns um alle Aspekte, die mit der Demontage, der Neuinstallation und der Inbetriebnahme der Maschine verbunden sind. Wir bieten auch einen Instandhaltungsservice an.&lt;br /&gt;\r\n&lt;br /&gt;\r\nWir sorgen f&uuml;r eine professionelle Vorbereitung und Sicherung der Maschine f&uuml;r den Stra&szlig;en- und Seetransport.&lt;br /&gt;\r\n&lt;br /&gt;\r\n&lt;strong&gt;Unser Angebot umfasst:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n    &lt;li&gt;Inspektion und technischer Bericht f&uuml;r die uns anvertraute Maschine,&lt;/li&gt;\r\n    &lt;li&gt;Demontage und Montage der Maschine am vorbezeichneten Ort,&lt;/li&gt;\r\n    &lt;li&gt;Organisation des Transports der Maschine an beliebigen Ort der Welt.&lt;/li&gt;\r\n&lt;/ul&gt;'),
(14, 'Maszyny dla poligrafii', '&lt;p&gt;Procesy technologiczne ulegają ciągłym zmianom - priorytetem stał sie czas i automatyzacja procesu. Dotyczy to także szeroko pojętej poligrafii i braku personelu Jednym z system&oacute;w mających na celu optymalizację czasu i ludzi są offline oczyszczarki arkusza. &lt;br /&gt;\r\n&lt;br /&gt;\r\nProsta i intuicyjna obsługa. polski interfejs pozwala na szybkie uzbrajanie maszyn bez konieczności stosowania specjalnych matryc. Wysztancowane arkusze są oczyszczane z pojedynczych pakiet&oacute;w użytk&oacute;w aż do uzyskania czystego ażuru. &lt;br /&gt;\r\n&lt;br /&gt;\r\nMożliwość r&oacute;żnorodnej konfiguracji pozwala nam dostarczyć maszynę od najprostszej do maksymalnie rozbudowanej wersji z automatycznym odkładaniem na palety. Atutem tego rozwiązania jest jednoosobowa obsługa maszyny&lt;/p&gt;', '', '', '', 1, 'Machines for printing', '&lt;p&gt;Technological advancements continue to evolve, emphasizing the importance of time efficiency and process automation. This trend extends to various sectors, including the printing industry, where addressing labor shortages and optimizing workflow are paramount. Tearing machines are one such system designed to streamline operations.&lt;br /&gt;\r\n&lt;br /&gt;\r\nFeaturing a user-friendly interface, these machines offer simple and intuitive operation. Their Polish interface facilitates quick setup without the need for special matrices. The machines effectively clean die-cut sheets in individual bundles until achieving a pristine, openwork finish.&lt;br /&gt;\r\n&lt;br /&gt;\r\nThe flexibility of these machines allows for various configurations, ranging from basic models to advanced versions equipped with automatic pallet placement. Notably, this solution enables single-operator functionality, enhancing operational efficiency.&lt;/p&gt;', 'Maschinen zum Drucken', '&lt;p&gt;Technologische Prozesse &auml;ndern sich st&auml;ndig &ndash; Zeit und Prozessautomatisierung stehen heute im Vordergrund. Das gilt auch f&uuml;r die Druckindustrie und den Personalmangel. Eines der Systeme zur Optimierung von Zeit und Arbeitskraft ist die automatische Bogenreinigungsmaschine.&lt;br /&gt;\r\n&lt;br /&gt;\r\nLeichte und intuitive Bedienung sowie die einfache Benutzeroberfl&auml;che erm&ouml;glichen schnelle Einrichtung der Maschine, ohne Verwendung spezieller Matrizen. Die gestanzten B&ouml;gen werden von einzelnen B&uuml;ndeln gereinigt, bis eine saubere Oberfl&auml;che erreicht ist.&lt;br /&gt;\r\n&lt;br /&gt;\r\nDie M&ouml;glichkeit verschiedener Konfigurationen erlaubt es uns, eine Maschine von der einfachsten bis zur umfangreichsten Version mit automatischer Palettierung zu liefern. Der Vorteil dieser L&ouml;sung ist die Ein-Mann-Bedienung.&lt;/p&gt;'),
(15, 'Załadunki i rozładunki', '&lt;p&gt;Bazując na rozmowach i oczekiwaniach klient&oacute;w PGM ENGINEERING postanowiło świadczyć r&oacute;wnież typowe usługi rozladunkowo-załadunkowe. &lt;br /&gt;\r\n&lt;br /&gt;\r\nPosiadany sprzęt i doświadczenie pozwalające nam podjąć się trudnych i nietypowych zadań.&lt;/p&gt;', '', '', '', 1, 'Loading and unloading', '&lt;p&gt;Drawing from discussions and expectations outlined by our clients, PGM ENGINEERING offers comprehensive unloading and loading services.&lt;br /&gt;\r\n&lt;br /&gt;\r\nOur experienced staff is equipped to manage even the most challenging and unconventional projects with precision and expertise.&lt;/p&gt;', 'Laden und Entladen', '&lt;p&gt;Um den Kundenerwartungen gerecht zu werden, hat PGM ENGINEERING beschlossen, auch typische Be- und Entladedienstleistungen anzubieten.&lt;br /&gt;\r\n&lt;br /&gt;\r\nWir haben die entsprechende Ausr&uuml;stung und die Erfahrung, um auch schwierige und ungew&ouml;hnliche Aufgaben zu &uuml;bernehmen.&lt;/p&gt;'),
(16, 'Wynajem widlak&oacute;w', '&lt;p&gt;Świadczymy r&oacute;wnież usługi wynajmu w&oacute;zk&oacute;w widłowych. Zapraszamy do kontaktu w celu zapoznania się z naszą ofertą wynajmu.&lt;/p&gt;', '', '', '', 1, 'Fork lift truck rental', '&lt;p&gt;We also offer forklift rental services. We encourage you to reach out to us to explore our offerings.&lt;/p&gt;', 'Vermietung von Gabelstaplern', '&lt;p&gt;Wir bieten auch die Vermietung von Gabelstaplern an. Setzen Sie sich mit uns in Kontakt, um sich mit unserem Mietangebot vertraut zu machen.&lt;/p&gt;');

